        SELECT
        
        FROM employee
        
            
                AND (
                username LIKE CONCAT('%', #{query.keyword}, '%')
                OR name LIKE CONCAT('%', #{query.keyword}, '%')
                OR no LIKE CONCAT('%', #{query.keyword}, '%')
                )
            

            
                AND role = #{query.role}
            

            
                AND status = #{query.status}
            
        
        ORDER BY created_time DESC
